def validate_quick_win(quick_win: str) -> dict:
    """Validate quick win is measurable and 24-72h achievable"""
    vague_terms = ["feel", "become", "understand", "learn", "improve", "better", "transform"]
    issues = []

    win_lower = quick_win.lower()

    # Check for vague terms
    for term in vague_terms:
        if term in win_lower and not any(x in win_lower for x in ["minutes", "hours", "days", "times", "$", "%", "calls", "pages"]):
            issues.append(f"Vague term '{term}' without measurable qualifier")

    # Check for time frame
    has_timeframe = any(x in win_lower for x in ["24", "48", "72", "day 1", "day 2", "day 3", "first", "within"])
    if not has_timeframe:
        issues.append("No clear timeframe specified")

    return {
        "passed": len(issues) == 0,
        "is_measurable": len(issues) == 0,
        "issues": issues,
        "recommendation": "Add specific metric or behavior proxy" if issues else "Quick win is valid"
    }

def validate_scope_creep(product_brief: dict) -> dict:
    """Check for scope creep indicators"""
    issues = []

    problem = product_brief.get("single_problem", "")
    promise = product_brief.get("single_promise", "")

    # Check for "and" in problem/promise (indicator of multiple jobs)
    if " and " in problem.lower():
        issues.append(f"Multiple problems detected: '{problem}'")
    if " and " in promise.lower():
        issues.append(f"Multiple promises detected: '{promise}'")

    # Check TOC length
    toc = product_brief.get("toc", [])
    if len(toc) > 12:
        issues.append(f"TOC has {len(toc)} sections (max 12 for LITE)")

    return {
        "passed": len(issues) == 0,
        "scope_clean": len(issues) == 0,
        "issues": issues
    }

def validate_action_assets(product: dict) -> dict:
    """Validate all required action assets are present"""
    required_assets = ["checklist", "tracker", "template"]
    issues = []

    assets = product.get("action_assets", {})

    for asset in required_assets:
        if asset not in assets or not assets[asset]:
            issues.append(f"Missing required asset: {asset}")

    # Check checklist has items
    if "checklist" in assets:
        items = assets["checklist"].get("items", [])
        if len(items) < 5:
            issues.append(f"Checklist has only {len(items)} items (min 5)")

    return {
        "passed": len(issues) == 0,
        "assets_complete": len(issues) == 0,
        "issues": issues
    }
